#!/usr/bin/env node
/**
 * Generate skills/scenario-map.md from skills/scenario-map.json.
 * Run from repo root: node scripts/generate-scenario-map.mjs
 * Output: skills/scenario-map.md (auto-generated; edit scenario-map.json instead)
 */
import { readFileSync, writeFileSync, existsSync } from 'fs';
import { dirname, join } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = join(__dirname, '..');
const skillsDir = join(root, 'skills');
const configPath = join(skillsDir, 'scenario-map.json');
const outPath = join(skillsDir, 'scenario-map.md');

if (!existsSync(configPath)) {
  console.error('skills/scenario-map.json not found');
  process.exit(1);
}

const config = JSON.parse(readFileSync(configPath, 'utf8'));

const link = (name) => `[${name}](./${name}/SKILL.md)`;

function renderScenario(s, i) {
  const optList = (s.optional || []).map((o) => {
    const note = s.optional_note && o === (s.optional || [])[0] ? ` (${s.optional_note})` : '';
    return `  - ${link(o)}${note}`;
  }).join('\n');
  const optSection = optList ? `\n- **Optional skills**:\n${optList}` : '';
  const triggersSection = (s.short_triggers && s.short_triggers.length)
    ? `\n- **Short triggers**: ${s.short_triggers.join(', ')}`
    : '';
  return `## ${i}) ${s.title}

- **When to use**: ${s.when_to_use}
- **Primary skill**: ${link(s.primary)}${optSection}${triggersSection}
- **Output**: ${s.output}
- **Stop condition**: ${s.stop_condition}`;
}

const routingRules = config.routing_rules || [];
const rulesText = routingRules.map((r, i) => `${i + 1}. ${r}`).join('\n');

const scenarios = config.scenarios || [];
const body = scenarios.map((s, i) => renderScenario(s, i + 1)).join('\n\n');

const doc = `# Scenario-Skill Map

*Auto-generated by \`scripts/generate-scenario-map.mjs\` from scenario-map.json. Edit the JSON, not this file.*

Use this map to select skills by work scenario instead of memorizing skill names.

For canonical skill registration, see [INDEX.md](./INDEX.md).

---

${body}

---

## Routing Rules

${rulesText}
`;

writeFileSync(outPath, doc, 'utf8');
console.log(`Written ${outPath}`);
